import React from 'react'
import Link from 'gatsby-link'
import Img from 'gatsby-image'

import './style.scss'

const Header = ({photo}) => (
  <div className="header">
    <div id="photo_cont">
      <Img
        title="Chris Gaeta"
        alt="Photo of Chris Gaeta"
        sizes={photo.sizes}
        style={{
          width: "160px",
          margin: "0 auto 10px",
          border: "5px solid black",
          borderRadius: "100%"
        }}/>
      <h1 id="name">Chris Gaeta</h1>
      <h2 id="title">UX Designer / Front End Developer</h2>
      <a
        id="githubLink"
        target="_blank"
        href="https://github.com/cgaeta"
        >Github</a>
      <hr
        style={{
          margin: "20px 0",
          height: 5
        }}/>
    </div>
  </div>
)

export default Header



