import React from "react"
import "./styles.scss"

const Job = ({ employer, location, title, start, end, duties }) =>
<div className="job">
  <h2 className="title">{title}</h2>
  <h3 className="employer">{employer}</h3>
  <h4 className="dates">{start} - {end}</h4>
  <h4 className="location">{location}</h4>
  <ul className="duties">
    {duties.map(d =>
      <li
        dangerouslySetInnerHTML={{
          __html: d.replace(
            /<(\w+)>([\w\W]+?)<\/\w+>/g,
            `<span class="$1">$2\</span>`)}}
      />
    )}
  </ul>
</div>

export default Job



