import React from 'react'
import Link from 'gatsby-link'

import Header from "../components/Header/";
import DropDown from "../components/DropDown/";
import Responsive from "../components/Responsive/";
import Job from "../components/Job/";
import Skills from "../components/Skills/";
import Education from "../components/Education/";
import BannerPreview from "../components/BannerPreview/";

import "./index.scss"

/*
  todo
*/

const hrBreak = {
  height: "3px",
  backgroundColor: "black"
};

class IndexPage extends React.Component {

  constructor(props) {
    super(props);
  }

  render() {
    return (
      <React.Fragment>
        <Header
          photo={this.props.data.photo} />
        <Education
          school="Purdue University"
          degrees={[
            {
              degree: "M.S.",
              program: "Computer Graphics Technology - User Experience Design",
              year: "2016"
            },
            {
              degree: "B.S.",
              program: "Computer Graphics Technology - Web Development",
              year: "2014"
            }
          ]} />
        <h2 style={{
          marginBottom: "5px"
        }}>Work</h2>
        <hr style={hrBreak} />
        {
          this.props.data.work.edges.map(({ node }) =>
          <Job {...node} />
          )
        }

        <h2 style={{
          marginBottom: "5px"
        }}>Skills</h2>
        <hr style={hrBreak} />
        <Responsive
          mobileWidth={540}
          wideWidth={960}
          props={({ mobile, narrow, wide }) => ({
            disabled: wide || narrow
          })}>
          {
            this.props.data.skills.edges.map(({ node: el }) =>
              <DropDown title={el.title} key={el.title}>
                <Skills skills={el.skills} />
              </DropDown>
            )
          }
        </Responsive>
        {/* <BannerPreview {...banners} /> */}
      </React.Fragment>
    )
  }
}

export default IndexPage

export const query = graphql`
  query portfolio {
    skills: allSkillsJson {
      edges {
        node {
          title
          skills
        }
      }
    }
    work: allWorkJson {
      edges {
        node {
          employer
          start
          end
          location
          title
          duties
        }
      }
    }
    photo: imageSharp(id: { regex: "/profile_photo/" }) {
      sizes(maxWidth: 1240 ) {
        ...GatsbyImageSharpSizes
      }
    }
  }
`



