import React from "react";
import ReactDom from "react-dom";
import "./styles.scss";

class BannerPreview extends React.Component {

  constructor(props) {
    super(props);

    this.state = {
      campaign: props.campaign,
      target: props.target,
      width: props.dim[0].width,
      height: props.dim[0].height
    }

    this.select = React.createRef();
    this.container = React.createRef();

    this.getWidth = this.getWidth.bind(this);
    this.scale = this.scale.bind(this);
    this.change = this.change.bind(this);
  }

  componentDidMount() {
    this.currentWidth = this.getWidth();
  }

  getWidth() {
    return this.currentWidth = this.container.current ?
      this.container.current.getBoundingClientRect().width :
      this.props.dim[0].width;
  }

  scale() {
    let scale = 1 / (this.state.width / this.getWidth());
    return this.currentWidth < this.state.width ?
      { transform: `scale(${1 / (this.state.width / this.currentWidth)})` } :
      {};
  }

  change(width, height) {
    this.setState(Object.assign({},
      this.state,
      {
        width,
        height
      }
    ));
  }

  render() {
    let { width, height, campaign, target } = this.state;
    return (
      <div
        id="bannerCont"
        ref={this.container}>
        <div id="bannerBtns">
          {this.props.dim.map(({width, height}, idx) =>
          <button
            onClick={() => this.change(width, height)}>
            {`${width}x${height}`}
          </button>
        )}
        </div>
        <iframe
          id="bannerPreview"
          src={`/banners/${campaign}_${width}x${height}_${target}/index.html`}
          width={width}
          height={height}
          frameborder="0"
          style={this.scale()}
        />
      </div>
    )
  }
}

export default BannerPreview;



